function climbStairs(n) {
  if (n <= 2) return n;
  // Bottom-up: seed dp[1] = 1, dp[2] = 2, then fill up to n.
  // Bonus: you only ever need the last TWO values — two variables suffice.

  return 0;
}

exercises.solutionCode:
function climbStairs(n) {
  if (n <= 2) return n;
  let prev2 = 1;
  let prev1 = 2;
  for (let i = 3; i <= n; i++) {
    const current = prev1 + prev2;
    prev2 = prev1;
    prev1 = current;
  }
  return prev1;
}
